+    match gr {
+        GraphRef::MultiUndirected { .. } | GraphRef::MultiDirected { .. } => {
+            Err(pyo3::exceptions::PyTypeError::new_err(format!(
+                "{operation} does not support MultiGraph or MultiDiGraph without losing parallel edges"
+            )))
+        }
+        _ => Ok(()),
+    }
